#!/bin/bash

echo "Enter two numbers: "
read a b

echo "1. Add 2. Subtract 3. Multiply 4. Divide"
echo "Enter choice: "
read ch

case $ch in
 1) result=$((a + b));;
 2) result=$((a - b));;
 3) result=$((a * b));;
 4) result=$((a / b));;
 *) echo "Invalid choice"; exit 1;;
esac

echo "Result: $result"
